// Simple observable store pattern
class Store {
  #state = {};
  #listeners = [];

  constructor(initialState) {
    this.#state = initialState;
  }

  getState() {
    return { ...this.#state }; // Return copy for immutability
  }

  subscribe(listener) {
    this.#listeners.push(listener);
    return () => {
      // Unsubscribe: remove listener
      this.#listeners = this.#listeners.filter(l => l !== listener);
    };
  }

  dispatch(action) {
    // Pure reducer function updates state
    this.#state = reducer(this.#state, action);
    // Notify all listeners
    this.#listeners.forEach(fn => fn(this.#state));
  }
}

// Pure reducer: (state, action) => newState
function reducer(state, action) {
  switch (action.type) {
    case 'ADD_ITEM':
      return { ...state, items: [...state.items, action.payload] };
    default:
      return state;
  }
}

// React Error Boundary example (conceptual)
class ErrorBoundary extends React.Component {
  state = { hasError: false };

  static getDerivedStateFromError(error) {
    // Update state to show fallback UI
    return { hasError: true };
  }

  componentDidCatch(error, info) {
    // Log error to reporting service
    logErrorToService(error, info.componentStack);
  }

  render() {
    if (this.state.hasError) {
      return <FallbackUI onRetry={() => this.setState({ hasError: false })} />;
    }
    return this.props.children;
  }
}

// Retry logic for fetch
async function fetchWithRetry(url, options, retries = 3) {
  for (let i = 0; i < retries; i++) {
    try {
      return await fetch(url, options);
    } catch (err) {
      if (i === retries - 1) throw err;
      await new Promise(res => setTimeout(res, 1000 * (i + 1))); // Exponential backoff
    }
  }
}

async function retry(fn, attempts = 3) {
  for (let i = 0; i < attempts; i++) {
    try {
      return await fn();
    } catch (err) {
      if (i === attempts - 1) throw err;
    }
  }
}

// Professional feature: Searchable data table with caching
// dataService.js - Pure, testable data layer
export async function fetchUsers(filters, { cache = new Map() } = {}) {
  const key = JSON.stringify(filters);

  // Check cache first
  if (cache.has(key)) {
    return cache.get(key);
  }

  // Fetch with error handling
  try {
    const response = await fetch(`/api/users?${new URLSearchParams(filters)}`);
    if (!response.ok) throw new Error(`HTTP ${response.status}`);

    const users = await response.json();
    cache.set(key, users); // Cache successful result
    return users;
  } catch (error) {
    console.error('Fetch failed:', error);
    throw error; // Let UI handle error state
  }
}

